import '../../../../../services/permission_service.dart';
import 'dart:io'; import 'package:excel/excel.dart'; import 'package:file_picker/file_picker.dart'; import 'package:flutter/material.dart'; import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../../../services/api_service.dart';
class ImportProductsScreen extends ConsumerStatefulWidget { const ImportProductsScreen({super.key}); @override ConsumerState<ImportProductsScreen> createState() => _ImportProductsScreenState(); }
class _ImportProductsScreenState extends ConsumerState<ImportProductsScreen> { File? _file; List<String> _cols=[]; Map<String,String?> _map={'sku':null,'name':null,'price':null}; double _prog=0; bool _upload=false;
  Future<void> _pick() async { final r = await FilePicker.platform.pickFiles(type: FileType.custom, allowedExtensions: ['xlsx']); if(r!=null) { setState((){_file=File(r.files.single.path!); _cols=[]; _map.updateAll((_,__)=>null);}); _read(); } }
  void _read() async { final b = await _file!.readAsBytes(); final e = Excel.decodeBytes(b); final s = e.tables.values.first; setState(()=>_cols = s.rows.first.map((c)=>c?.value.toString()??'').toList()); }
  Future<void> _uploadAll() async { if(_file==null||_map.values.any((v)=>v==null)) return; setState((){_upload=true; _prog=0;}); final b = await _file!.readAsBytes(); final e = Excel.decodeBytes(b); final s = e.tables.values.first; final rows = s.rows.skip(1).toList(); final api = ref.read(apiServiceProvider); final batch = <Map<String,dynamic>>[]; for(int i=0;i<rows.length;i++) { final item = <String,dynamic>{}; for(var ent in _map.entries) { final idx = _cols.indexOf(ent.value!); if(idx!=-1) item[ent.key] = rows[i][idx]?.value; } if(item['sku']!=null) batch.add(item); if(batch.length>=20 || i==rows.length-1) { await api.importProductsBatch(batch); batch.clear(); } setState(()=>_prog = (i+1)/rows.length); } ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('تم الاستيراد'))); setState(()=>_upload=false); }
  @override Widget build(BuildContext context) => Directionality(textDirection: TextDirection.rtl, child: Scaffold(appBar: AppBar(title: const Text('استيراد من Excel')), body: Padding(padding: const EdgeInsets.all(24), child: Column(children: [ Row(children: [Expanded(child: Text(_file?.path.split('/').last??'لم يتم اختيار ملف')), ElevatedButton(onPressed: _pick, child: const Text('استعراض'))]), if(_cols.isNotEmpty) ...[ const SizedBox(height:24), Table(border: TableBorder.all(), children: [ const TableRow(children: [Text('حقل'), Text('عمود')]), ..._map.keys.map((f)=>TableRow(children: [Text(f), DropdownButton<String>(value: _map[f], items: _cols.map((c)=>DropdownMenuItem(value:c, child:Text(c))).toList(), onChanged: (v)=>setState(()=>_map[f]=v))])) ]), const SizedBox(height:24), if(_upload) LinearProgressIndicator(value: _prog), ElevatedButton(onPressed: _upload?null:_uploadAll, child: const Text('رفع للخادم')) ] ])))); }
